3642 /// the other bits. We know that at least 1 bit is always equal to the sign bit
3643 /// (itself), but other cases can give us information. For example, immediately
3644 /// after an "ashr X, 2", we know that the top 3 bits are all equal to each
3645 /// other, so we return 3. For vectors, return the number of sign bits for the
3646 /// vector element with the minimum number of known sign bits of the demanded
3647 /// elements in the vector specified by DemandedElts.
3648 static unsigned ComputeNumSignBitsImpl(const Value *V,
3649                                        const APInt &DemandedElts,
3650                                        unsigned Depth, const SimplifyQuery &Q) {
3651   Type *Ty = V->getType();
3652 #ifndef NDEBUG
3653   assert(Depth <= MaxAnalysisRecursionDepth && "Limit Search Depth");
3654 
3655   if (auto *FVTy = dyn_cast<FixedVectorType>(Ty)) {
3656     assert(
3657         FVTy->getNumElements() == DemandedElts.getBitWidth() &&
3658         "DemandedElt width should equal the fixed vector number of elements");
3659   } else {
3660     assert(DemandedElts == APInt(1, 1) &&
3661            "DemandedElt width should be 1 for scalars");
