3665   // We return the minimum number of sign bits that are guaranteed to be present
3666   // in V, so for undef we have to conservatively return 1.  We don't have the
3667   // same behavior for poison though -- that's a FIXME today.
3668 
3669   Type *ScalarTy = Ty->getScalarType();
3670   unsigned TyBits = ScalarTy->isPointerTy() ?
3671     Q.DL.getPointerTypeSizeInBits(ScalarTy) :
3672     Q.DL.getTypeSizeInBits(ScalarTy);
