3674   unsigned Tmp, Tmp2;
3675   unsigned FirstAnswer = 1;
3676 
3677   // Note that ConstantInt is handled by the general computeKnownBits case
3678   // below.
3679 
3680   if (Depth == MaxAnalysisRecursionDepth)
3681     return 1;
