3683   if (auto *U = dyn_cast<Operator>(V)) {
3684     switch (Operator::getOpcode(V)) {
3685     default: break;
3686     case Instruction::SExt:
3687       Tmp = TyBits - U->getOperand(0)->getType()->getScalarSizeInBits();
3688       return ComputeNumSignBits(U->getOperand(0), Depth + 1, Q) + Tmp;
