3690     case Instruction::SDiv: {
3691       const APInt *Denominator;
3692       // sdiv X, C -> adds log(C) sign bits.
3693       if (match(U->getOperand(1), m_APInt(Denominator))) {
3694 
3695         // Ignore non-positive denominator.
3696         if (!Denominator->isStrictlyPositive())
