3698 
3699         // Calculate the incoming numerator bits.
3700         unsigned NumBits = ComputeNumSignBits(U->getOperand(0), Depth + 1, Q);
3701 
3702         // Add floor(log(C)) bits to the numerator bits.
3703         return std::min(TyBits, NumBits + Denominator->logBase2());
3704       }
3705       break;
3706     }
3707 
3708     case Instruction::SRem: {
