3832 
3833           // If the input is known to be positive (the sign bit is known clear),
3834           // the output of the NEG has the same number of sign bits as the
3835           // input.
3836           if (Known.isNonNegative())
3837             return Tmp2;
3838 
3839           // Otherwise, we treat this like a SUB.
3840         }
3841 
3842       // Sub can have at most one carry bit.  Thus we know that the output
3843       // is, at worst, one more bit than the inputs.
3844       Tmp = ComputeNumSignBits(U->getOperand(0), Depth + 1, Q);
3845       if (Tmp == 1) break;
3846       return std::min(Tmp, Tmp2) - 1;
3847 
3848     case Instruction::Mul: {
3849       // The output of the Mul can be at most twice the valid bits in the
3850       // inputs.
3851       unsigned SignBitsOp0 = ComputeNumSignBits(U->getOperand(0), Depth + 1, Q);
3852       if (SignBitsOp0 == 1) break;
3853       unsigned SignBitsOp1 = ComputeNumSignBits(U->getOperand(1), Depth + 1, Q);
3854       if (SignBitsOp1 == 1) break;
3855       unsigned OutValidBits =
3856           (TyBits - SignBitsOp0 + 1) + (TyBits - SignBitsOp1 + 1);
3857       return OutValidBits > TyBits ? 1 : TyBits - OutValidBits + 1;
3858     }
3859 
3860     case Instruction::PHI: {
3861       const PHINode *PN = cast<PHINode>(U);
3862       unsigned NumIncomingValues = PN->getNumIncomingValues();
3863       // Don't analyze large in-degree PHIs.
3864       if (NumIncomingValues > 4) break;
3865       // Unreachable blocks may have zero-operand PHI nodes.
3866       if (NumIncomingValues == 0) break;
3867 
3868       // Take the minimum of all incoming values.  This can't infinitely loop
3869       // because of our depth threshold.
3870       SimplifyQuery RecQ = Q;
3871       Tmp = TyBits;
3872       for (unsigned i = 0, e = NumIncomingValues; i != e; ++i) {
3873         if (Tmp == 1) return Tmp;
3874         RecQ.CxtI = PN->getIncomingBlock(i)->getTerminator();
3875         Tmp = std::min(
3876             Tmp, ComputeNumSignBits(PN->getIncomingValue(i), Depth + 1, RecQ));
3877       }
3878       return Tmp;
